import{_ as e,p as c,q as i,a1 as l}from"./framework-96b046e1.js";const d="/images/lm2596-5-01.png",o="/images/lm2596-001.png",a="/images/lm2596-002.png",p="/images/lm2596-003.png",r={},t=l('<p>在此分享一些我使用的 DC-DC 电源芯片，包括线性稳压芯片和开关型稳压芯片。</p><p>DC-DC 分为升压和降压两种，降压使用的多一点，下面分享出我使用的电源芯片和电路图。</p><h2 id="dcdc-降压芯片" tabindex="-1"><a class="header-anchor" href="#dcdc-降压芯片" aria-hidden="true">#</a> DCDC 降压芯片</h2><ul><li><p>LM2596</p><ul><li>输出：3.3V、5V、12V 和可调输出版本</li><li>可调输出电压范围：1.2V 至 37V</li><li>封装：TO-263-5，TO-220-5</li><li>输出负载电流为 3A</li><li>输入电压范围高达 40V</li><li>非同步</li></ul></li><li><p>LMR33630</p><ul><li>TI 公司的体积更小</li><li>同步</li></ul></li><li><p>XL1509</p><ul><li>封装：SOIC-8</li><li>输入：4.5V~40V</li><li>输出：输出电压有多个版本可选，也有可调型号</li><li>输出电流：最大 2A</li></ul></li></ul><h2 id="lm2596" tabindex="-1"><a class="header-anchor" href="#lm2596" aria-hidden="true">#</a> LM2596</h2><p>先来看一个固定 5V 输出的电路：</p><p><img src="'+d+'" alt=""></p><p>这个电路需要非常少的元器件，这几个外围器件都是必须的，<code>D1</code> 是续流二极管，<code>L1</code> 是储能电感，<code>CIN</code>和<code>COUT</code> 是滤波电容。</p><p><code>LM2596</code> 的第五引脚为使能控制，大约电压低于 <code>1.3V</code> 芯片工作，大于 <code>1.3V</code> 芯片关闭，正常情况直接接 <code>GND</code>。</p><p><code>D1</code> 的型号为 <code>1N5824</code> 的肖特基二极管（<code>30V 5A</code>），我们也可以选择其他型号只有参数不低于该型号的就行，如：<code>SS53</code>、<code>SS54</code>等。</p><p>LM2596 内部框图： <img src="'+o+'" alt=""></p><h3 id="延迟启动电路" tabindex="-1"><a class="header-anchor" href="#延迟启动电路" aria-hidden="true">#</a> 延迟启动电路</h3><p>电路工作原理是刚上电的时候由于电容两端电压不能突变，所有这时经过电阻分压后芯片5号引脚为高，这样芯片不工作，当慢慢电容充满电后5号引脚有电阻R2拉低，拉低后芯片开始工作。</p><p><img src="'+a+'" alt=""></p><h3 id="欠压保护" tabindex="-1"><a class="header-anchor" href="#欠压保护" aria-hidden="true">#</a> 欠压保护</h3><p><img src="'+p+'" alt=""></p>',16),s=[t];function n(h,m){return c(),i("div",null,s)}const u=e(r,[["render",n],["__file","dc-dc-power.html.vue"]]);export{u as default};
